import{_ as a,o as s,c as i,ag as n}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"第 8 章：向量搜索与嵌入","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/08-vector-search.md","filePath":"chapters/08-vector-search.md"}'),d={name:"chapters/08-vector-search.md"};function t(c,e,o,r,l,h){return s(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="第-8-章-向量搜索与嵌入" tabindex="-1">第 8 章：向量搜索与嵌入 <a class="header-anchor" href="#第-8-章-向量搜索与嵌入" aria-label="Permalink to &quot;第 8 章：向量搜索与嵌入&quot;">​</a></h1><blockquote><p>全文检索能找到精确的关键词匹配，但语义搜索才能理解用户真正想要什么。qmd 在本地 SQLite 数据库中集成了 sqlite-vec 扩展，将文档转化为高维向量，用余弦相似度衡量语义距离。这一章我们将深入 <code>src/store.ts</code> 和 <code>src/llm.ts</code>，看看一个完全离线的向量搜索系统是如何从表结构创建、文档嵌入、到最终检索一步步搭建起来的。</p></blockquote><h2 id="向量表的创建与校验" tabindex="-1">向量表的创建与校验 <a class="header-anchor" href="#向量表的创建与校验" aria-label="Permalink to &quot;向量表的创建与校验&quot;">​</a></h2><h3 id="ensurevectableinternal-的职责" tabindex="-1">ensureVecTableInternal() 的职责 <a class="header-anchor" href="#ensurevectableinternal-的职责" aria-label="Permalink to &quot;ensureVecTableInternal() 的职责&quot;">​</a></h3><p>向量搜索的基础是存储结构。<code>src/store.ts</code> 的 <code>ensureVecTableInternal()</code> 函数（第 962-977 行）负责创建和维护 vec0 虚拟表。这张表是整个向量检索的核心存储，使用 sqlite-vec 提供的 vec0 模块：</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> VIRTUAL </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TABLE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> vectors_vec </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">USING</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> vec0(</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  hash_seq </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TEXT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> PRIMARY KEY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  embedding </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">float</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[N] distance_metric</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cosine</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>其中 <code>N</code> 是嵌入模型输出的维度数，由首次生成的向量动态确定。主键 <code>hash_seq</code> 采用 <code>&quot;{hash}_{seq}&quot;</code> 的格式，将文档哈希与分块序号拼接，确保每个文档片段都有唯一标识。距离度量选择了 <code>cosine</code>，即余弦距离，这是文本语义检索中最常用的度量方式。</p><h3 id="模式校验与重建" tabindex="-1">模式校验与重建 <a class="header-anchor" href="#模式校验与重建" aria-label="Permalink to &quot;模式校验与重建&quot;">​</a></h3><p><code>ensureVecTableInternal()</code> 不只是简单地执行 <code>CREATE TABLE</code>。它在创建前会检查已有表的维度和模式是否匹配当前配置。校验的要点包括：主键字段是否为 <code>hash_seq</code>、距离度量是否为 cosine、向量维度是否与当前嵌入模型一致。</p><p>如果检测到模式不匹配——比如用户切换了嵌入模型导致维度变化——函数会果断地 DROP 旧表并重新创建。这个设计看似激进，但在实际场景中是合理的：向量维度不同意味着旧数据完全不可用，保留它们反而会导致查询错误。</p><h2 id="嵌入管道的三个阶段" tabindex="-1">嵌入管道的三个阶段 <a class="header-anchor" href="#嵌入管道的三个阶段" aria-label="Permalink to &quot;嵌入管道的三个阶段&quot;">​</a></h2><h3 id="查询文本的格式化" tabindex="-1">查询文本的格式化 <a class="header-anchor" href="#查询文本的格式化" aria-label="Permalink to &quot;查询文本的格式化&quot;">​</a></h3><p><code>src/llm.ts</code> 中的 <code>formatQueryForEmbedding()</code> 函数（第 38-44 行）负责将用户的原始查询包装成嵌入模型期望的输入格式。这里有一个重要的细节：不同的嵌入模型需要不同的 prompt 格式。</p><p>对于默认的 embeddinggemma 模型，格式为：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>task: search result | query: {query}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>而对于 Qwen3-Embedding 系列模型，格式则变为：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Instruct: Retrieve relevant documents for the given query</span></span>
<span class="line"><span>Query: {query}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>模型检测通过 <code>isQwen3EmbeddingModel()</code> 函数（<code>llm.ts</code> 第 29-31 行）完成，它使用正则表达式匹配模型名称中的 Qwen3 特征串。这种按模型类型分发格式的策略，保证了不同嵌入模型都能在最佳 prompt 下工作。</p><h3 id="文档文本的格式化" tabindex="-1">文档文本的格式化 <a class="header-anchor" href="#文档文本的格式化" aria-label="Permalink to &quot;文档文本的格式化&quot;">​</a></h3><p>与查询格式化对应，<code>formatDocForEmbedding()</code> 负责文档侧的格式化。文档嵌入使用的格式为：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>task: search document | title: {title} | text: {text}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>查询和文档使用不同的 task 前缀（<code>search result</code> vs <code>search document</code>），这是非对称嵌入（asymmetric embedding）的经典做法。搜索引擎中查询通常很短，文档通常很长，两者的语义空间分布不同，使用不同的 task 标记可以让模型更好地将它们映射到共同的向量空间中。</p><h3 id="getembedding-的封装" tabindex="-1">getEmbedding() 的封装 <a class="header-anchor" href="#getembedding-的封装" aria-label="Permalink to &quot;getEmbedding() 的封装&quot;">​</a></h3><p><code>src/store.ts</code> 的 <code>getEmbedding()</code> 函数（第 2910-2917 行）是一个简洁的封装层，将底层的 embed 调用与上层的格式化逻辑粘合在一起。它接受文本和类型参数（query 或 doc），自动调用对应的格式化函数，然后交给 LLM 会话执行实际的嵌入计算。这层封装使得调用方不需要关心格式化细节。</p><h2 id="向量检索的实现" tabindex="-1">向量检索的实现 <a class="header-anchor" href="#向量检索的实现" aria-label="Permalink to &quot;向量检索的实现&quot;">​</a></h2><h3 id="searchvec-的两步查询策略" tabindex="-1">searchVec() 的两步查询策略 <a class="header-anchor" href="#searchvec-的两步查询策略" aria-label="Permalink to &quot;searchVec() 的两步查询策略&quot;">​</a></h3><p><code>src/store.ts</code> 的 <code>searchVec()</code> 函数（第 2820-2904 行）是向量检索的核心。这个函数最值得关注的设计决策是它的两步查询架构。</p><p><strong>第一步</strong>：直接查询 <code>vectors_vec</code> 虚拟表，使用 sqlite-vec 提供的 MATCH 语法：</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> embedding </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">MATCH</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ? </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AND</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> k </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ?</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这一步只返回 <code>hash_seq</code> 和对应的距离值，不涉及任何 JOIN 操作。</p><p><strong>第二步</strong>：拿到候选的 <code>hash_seq</code> 列表后，再通过常规 SQL JOIN <code>content_vectors</code>、<code>documents</code>、<code>content</code> 等表，获取文件路径、标题、正文等元数据。</p><h3 id="为什么不用单步-join" tabindex="-1">为什么不用单步 JOIN？ <a class="header-anchor" href="#为什么不用单步-join" aria-label="Permalink to &quot;为什么不用单步 JOIN？&quot;">​</a></h3><p>这个两步策略并非过度设计，而是一个必要的工程妥协。正如 PR #23 中记录的，sqlite-vec 在执行包含 JOIN 的查询时会出现挂起（hang）的问题。将向量匹配与元数据查询分离，绕过了这个已知的 bug，同时也让每一步的查询逻辑更简单、更易调试。</p><h3 id="去重与评分" tabindex="-1">去重与评分 <a class="header-anchor" href="#去重与评分" aria-label="Permalink to &quot;去重与评分&quot;">​</a></h3><p><code>searchVec()</code> 在拿到结果后还需要做去重处理。由于一个文档会被切分为多个 chunk，同一个文件可能返回多条结果。函数按 <code>filepath</code> 去重，只保留距离最小（相似度最高）的那条记录。</p><p>最终的评分计算公式为：<code>score = 1 - cosine_distance</code>。cosine_distance 的范围是 [0, 2]，其中 0 表示向量完全相同。转换后 score 的范围是 [-1, 1]，1 表示完全匹配，这与直觉一致。</p><h2 id="批量嵌入的工程细节" tabindex="-1">批量嵌入的工程细节 <a class="header-anchor" href="#批量嵌入的工程细节" aria-label="Permalink to &quot;批量嵌入的工程细节&quot;">​</a></h2><h3 id="generateembeddings-的完整流程" tabindex="-1">generateEmbeddings() 的完整流程 <a class="header-anchor" href="#generateembeddings-的完整流程" aria-label="Permalink to &quot;generateEmbeddings() 的完整流程&quot;">​</a></h3><p><code>src/store.ts</code> 的 <code>generateEmbeddings()</code> 函数（第 1303-1447 行）负责为所有待处理的文档生成嵌入向量。这是一个复杂的批处理流程，包含多层优化。</p><p>首先，<code>getPendingEmbeddingDocs()</code> 通过 LEFT JOIN <code>content_vectors</code> 表找出尚未生成嵌入的文档。这个 JOIN 的逻辑很直白：如果 <code>content_vectors</code> 中没有对应记录，说明该文档还没有被嵌入。</p><p>然后，<code>buildEmbeddingBatches()</code> 将待处理文档组织成批次。批次受两个约束限制：<code>maxDocsPerBatch</code>（默认 64 个文档）和 <code>maxBatchBytes</code>（默认 64MB）。双重限制确保既不会一次性加载过多文档导致内存溢出，也不会因单个超大文档撑爆内存。</p><h3 id="分块与嵌入" tabindex="-1">分块与嵌入 <a class="header-anchor" href="#分块与嵌入" aria-label="Permalink to &quot;分块与嵌入&quot;">​</a></h3><p>对于每个批次中的文档，<code>chunkDocumentByTokens()</code> 将长文档按 token 数切分为多个片段。切分是必要的，因为嵌入模型有输入长度限制，且过长的文本会稀释语义信号。</p><p>嵌入操作以 32 个 chunk 为一组批量执行。批量嵌入比逐条嵌入高效得多，因为它能充分利用 GPU 的并行计算能力，减少模型调用的开销。</p><h3 id="容错机制" tabindex="-1">容错机制 <a class="header-anchor" href="#容错机制" aria-label="Permalink to &quot;容错机制&quot;">​</a></h3><p><code>generateEmbeddings()</code> 内建了一个重要的容错策略：如果批量嵌入失败，会自动降级为逐条嵌入。这意味着即使某些文档格式异常导致批量处理出错，其他正常文档仍然能够完成嵌入，不会因为一颗老鼠屎坏了一锅粥。</p><h3 id="维度的动态确定" tabindex="-1">维度的动态确定 <a class="header-anchor" href="#维度的动态确定" aria-label="Permalink to &quot;维度的动态确定&quot;">​</a></h3><p>一个巧妙的实现细节是：向量表的维度在第一个 chunk 成功嵌入后才确定。<code>generateEmbeddings()</code> 用第一个 chunk 的返回向量长度来调用 <code>ensureVecTableInternal()</code>，创建或校验表结构。这使得 qmd 无需在配置中硬编码维度，切换嵌入模型时也无需手动修改配置。</p><h3 id="数据写入" tabindex="-1">数据写入 <a class="header-anchor" href="#数据写入" aria-label="Permalink to &quot;数据写入&quot;">​</a></h3><p>每个成功嵌入的 chunk 通过 <code>insertEmbedding()</code> 写入两张表：<code>content_vectors</code> 存储元数据（文档哈希、序号、chunk 文本等），<code>vectors_vec</code> 存储实际的向量数据。主键 <code>hash_seq</code> 在两张表之间建立关联，格式为 <code>&quot;{hash}_{seq}&quot;</code>，其中 <code>hash</code> 标识文档，<code>seq</code> 标识 chunk 序号。</p><h2 id="默认模型配置" tabindex="-1">默认模型配置 <a class="header-anchor" href="#默认模型配置" aria-label="Permalink to &quot;默认模型配置&quot;">​</a></h2><h3 id="三个模型的分工" tabindex="-1">三个模型的分工 <a class="header-anchor" href="#三个模型的分工" aria-label="Permalink to &quot;三个模型的分工&quot;">​</a></h3><p>qmd 的向量搜索涉及三个本地模型，各司其职。<code>src/store.ts</code> 第 42-44 行定义了它们的默认值：</p><ul><li><strong>嵌入模型</strong>（<code>DEFAULT_EMBED_MODEL</code>）：<code>embeddinggemma</code>，负责将文本转为向量。这是 Google 发布的轻量级嵌入模型，在 MTEB 等基准测试中表现优异。</li><li><strong>重排模型</strong>：<code>ExpedientFalcon/qwen3-reranker:0.6b-q8_0</code>，负责对候选结果进行精排。0.6B 参数量、Q8_0 量化，在精度和速度之间取得了平衡。</li><li><strong>查询生成模型</strong>：<code>Qwen/Qwen3-1.7B</code>，负责查询扩展，将自然语言问题转化为多种类型的子查询。</li></ul><p>三个模型的选择体现了 qmd 的设计原则：优先选择小模型，确保在消费级硬件上也能流畅运行。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><p>本章剖析了 qmd 向量搜索系统的完整链路。从 <code>ensureVecTableInternal()</code> 创建和校验 vec0 虚拟表，到 <code>formatQueryForEmbedding()</code> 和 <code>formatDocForEmbedding()</code> 为不同模型适配输入格式，再到 <code>searchVec()</code> 用两步查询绕过 sqlite-vec 的 JOIN 缺陷，最后到 <code>generateEmbeddings()</code> 的批处理流水线——每一层都在解决具体的工程问题。向量搜索不是简单地调用一个 API，而是从存储格式、查询策略、批处理优化到容错降级的系统工程。qmd 在 SQLite 这个看似简单的基础上，搭建了一套完整且可靠的本地语义检索方案。</p>`,57)])])}const b=a(d,[["render",t]]);export{u as __pageData,b as default};
